def build_markdown() -> str:
    now = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    lines = [
        "# Стратегия визуализаций",
        "",
        f"Дата формирования: `{now}`.",
        "",
        "Стратегия ориентирована на параметризуемые отчеты `month`, `quarter`, `year` и использует единый report scope dataset.",
        "",
        "| № | Название | Тип | Что показывает | Управленческий вопрос | Управленческий смысл | Аналитическая ценность | Возможный инсайт | Сложность | Приоритет | Применимость | Необходимые поля | Среда |",
        "|---:|---|---|---|---|---|---|---|---|---|---|---|---|",
    ]
    for item in VISUALIZATIONS:
        lines.append(
            "| "
            f"{item.number} | {item.name} | {item.chart_type} | {item.shows} | "
            f"{item.management_question} | {item.management_meaning} | {item.analytical_value} | "
            f"{item.possible_insight} | {item.complexity} | {item.priority} | {item.applicability} | "
            f"`{item.required_fields}` | {item.environment} |"
        )
    lines.extend(
        [
            "",
            "## Покрытие обязательных направлений",
            "",
            "- Объем размещения: визуализации 1, 2, 8, 13, 21.",
            "- Предложение: визуализации 2, 4, 15, 21.",
            "- Спрос: визуализации 3, 4, 14, 19.",
            "- Bid-to-cover: визуализации 4, 19.",
            "- Средневзвешенная доходность: визуализации 5, 6, 10, 14, 24.",
            "- Минимальная, средневзвешенная и максимальная доходность по видам ОФЗ: визуализация 6.",
            "- Тип ОФЗ: визуализации 6, 7, 20.",
            "- Срок обращения: визуализации 8, 11, 20, 24.",
            "- Формат размещения: визуализации 9, 20, 25.",
            "- Аналитика доходности ОФЗ-ПД: визуализация 10.",
            "- Динамика кривой доходности: визуализация 11.",
            "- Heatmap: визуализации 12, 22.",
            "- Waterfall: визуализации 13, 21.",
            "- Scatter/bubble: визуализации 14, 18, 24.",
            "- Correlation matrix: визуализация 15.",
            "- Volatility: визуализация 16.",
            "- Concentration: визуализация 17.",
            "- Clustering: визуализация 18.",
            "- Risk quadrant: визуализация 19.",
            "- Sankey diagram: визуализация 20.",
            "- Factor decomposition: визуализация 21.",
            "",
        ]
    )
    return "\n".join(lines)


def main() -> int:
    OUTPUT_DOC.parent.mkdir(parents=True, exist_ok=True)
    OUTPUT_DOC.write_text(build_markdown(), encoding="utf-8")
    print(f"Стратегия визуализаций записана: {OUTPUT_DOC}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
